const config = $input.first().json || {};
const required = ['AIRTABLE_API_KEY', 'AIRTABLE_BASE_ID'];
const missing = required.filter((name) => !config[name] || String(config[name]).startsWith('PASTE_'));
if (missing.length) {
  throw new Error('Fill these fields in the "Airtable Setup Config" node: ' + missing.join(', '));
}

const AIRTABLE_API_KEY = config.AIRTABLE_API_KEY;
const AIRTABLE_BASE_ID = config.AIRTABLE_BASE_ID;
const META_BASE = 'https://api.airtable.com/v0/meta/bases/' + AIRTABLE_BASE_ID;
const httpRequest = this.helpers.httpRequest.bind(this);

if (!/^app[a-zA-Z0-9]+$/.test(AIRTABLE_BASE_ID)) {
  throw new Error('AIRTABLE_BASE_ID must be the Airtable base id from the base URL. It should start with "app", for example appXXXXXXXXXXXXXX. Current value: ' + AIRTABLE_BASE_ID);
}

const schemas = [
  {
    name: 'Sources',
    description: 'Discovered and approved source registry for photography open calls.',
    fields: [
      { name: 'Source Key', type: 'singleLineText' },
      { name: 'Source URL', type: 'url' },
      { name: 'Domain', type: 'singleLineText' },
      { name: 'Source Type', type: 'singleSelect', options: { choices: [
        { name: 'Search result' },
        { name: 'Aggregator' },
        { name: 'Museum' },
        { name: 'Gallery' },
        { name: 'Festival' },
        { name: 'Social indexed' },
        { name: 'Other' },
      ] } },
      { name: 'Status', type: 'singleSelect', options: { choices: [
        { name: 'Candidate' },
        { name: 'Approved' },
        { name: 'Rejected' },
        { name: 'Dormant' },
      ] } },
      { name: 'Confidence', type: 'number', options: { precision: 2 } },
      { name: 'First Seen', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Last Seen', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Last Discovery Checked', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Last Direct Checked', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Discovery Provider', type: 'singleSelect', options: { choices: [
        { name: 'Brave' },
        { name: 'SerpAPI' },
        { name: 'Tavily' },
        { name: 'Direct' },
        { name: 'Manual' },
      ] } },
      { name: 'Provider Cost Class', type: 'singleSelect', options: { choices: [
        { name: 'Free direct HTTP' },
        { name: 'Low-cost search' },
        { name: 'Fallback search' },
        { name: 'Avoid daily use' },
      ] } },
      { name: 'Hit Count', type: 'number', options: { precision: 0 } },
      { name: 'Notes', type: 'multilineText' },
    ],
  },
  {
    name: 'Open Calls',
    description: 'Daily discovered free photography open calls with online submission.',
    fields: [
      { name: 'Title', type: 'singleLineText' },
      { name: 'URL', type: 'url' },
      { name: 'Canonical URL', type: 'url' },
      { name: 'Deadline', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Summary', type: 'multilineText' },
      { name: 'Fee Status', type: 'singleSelect', options: { choices: [
        { name: 'Free' },
        { name: 'No required fee' },
        { name: 'Unknown' },
        { name: 'Paid required fee' },
      ] } },
      { name: 'Submission Type', type: 'singleSelect', options: { choices: [
        { name: 'Online' },
        { name: 'Email' },
        { name: 'Platform' },
        { name: 'Unknown' },
      ] } },
      { name: 'Source', type: 'singleLineText' },
      { name: 'Confidence', type: 'number', options: { precision: 2 } },
      { name: 'Status', type: 'singleSelect', options: { choices: [
        { name: 'Active' },
        { name: 'Needs review' },
        { name: 'Rejected' },
        { name: 'Expired' },
      ] } },
      { name: 'First Seen', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Last Checked', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Rejection Reason', type: 'multilineText' },
      { name: 'My Decision', type: 'singleSelect', options: { choices: [
        { name: 'To review' },
        { name: 'Apply' },
        { name: 'Maybe' },
        { name: 'Skip' },
        { name: 'Applied' },
      ] } },
      { name: 'Notes', type: 'multilineText' },
      { name: 'Priority', type: 'singleSelect', options: { choices: [
        { name: 'High' },
        { name: 'Medium' },
        { name: 'Low' },
      ] } },
    ],
  },
];

async function airtableMeta(path, options = {}) {
  const requestOptions = {
    method: options.method || 'GET',
    url: META_BASE + path,
    headers: {
      Authorization: 'Bearer ' + AIRTABLE_API_KEY,
      'Content-Type': 'application/json',
      ...(options.headers || {}),
    },
    json: true,
  };
  if (options.body) {
    requestOptions.body = typeof options.body === 'string' ? JSON.parse(options.body) : options.body;
  }
  try {
    return await httpRequest(requestOptions);
  } catch (error) {
    const hint = path === '/tables'
      ? ' Check that AIRTABLE_BASE_ID is the base id from an opened Airtable base URL, and that the token has access to this base plus schema.bases:read and schema.bases:write scopes.'
      : '';
    throw new Error('Airtable metadata API failed for ' + path + ' on base ' + AIRTABLE_BASE_ID + ': ' + (error.message || String(error)) + hint);
  }
}

function cleanField(field) {
  const out = { name: field.name, type: field.type };
  if (field.options) out.options = field.options;
  return out;
}

let tablesResponse = await airtableMeta('/tables', { method: 'GET' });
const actions = [];

for (const schema of schemas) {
  let table = (tablesResponse.tables || []).find((candidate) => candidate.name === schema.name);
  if (!table) {
    const created = await airtableMeta('/tables', {
      method: 'POST',
      body: JSON.stringify({
        name: schema.name,
        description: schema.description,
        fields: schema.fields.map(cleanField),
      }),
    });
    actions.push('Created table ' + schema.name);
    table = created;
    tablesResponse = await airtableMeta('/tables', { method: 'GET' });
  }

  table = (tablesResponse.tables || []).find((candidate) => candidate.name === schema.name);
  const existingFieldNames = new Set((table.fields || []).map((field) => field.name));
  for (const field of schema.fields) {
    if (existingFieldNames.has(field.name)) continue;
    await airtableMeta('/tables/' + table.id + '/fields', {
      method: 'POST',
      body: JSON.stringify(cleanField(field)),
    });
    actions.push('Created field ' + schema.name + '.' + field.name);
  }
}

if (!actions.length) actions.push('Airtable schema already matches expected setup');

return [{
  json: {
    ok: true,
    baseId: AIRTABLE_BASE_ID,
    actions,
    requiredTables: schemas.map((schema) => schema.name),
  },
}];
